// Worked focus: httpsts-webhook-signature-freshness — Verify provider identity, algorithm, exact bytes, timestamp freshness, constant-behavior signature comparison, key rotation, and failure disclosure before parsing.
// Evidence: httpsts-worked-http-server-ts-webhooks-ssrf-abuse-5
// Competency: httpsts-worked-http-server-ts-webhooks-ssrf-abuse-5.
// Case 9036: privacy-sensitive records API using conditional requests.
// Operating constraint: retain a screen-reader-readable decision trace.
// Changed case: saturate one tenant budget while another tenant remains serviceable.
function worked_http_server_ts_webhooks_ssrf_abuse_5(signatureValid: boolean, ageSeconds: number, replaySeen: boolean, publicDestination: boolean): { status: number; enqueue: boolean; egress: boolean } {
  const fresh = ageSeconds >= 0 && ageSeconds <= 300;
  if (!signatureValid || !fresh) return { status: 401, enqueue: false, egress: false };
  if (replaySeen) return { status: 409, enqueue: false, egress: false };
  if (!publicDestination) return { status: 403, enqueue: false, egress: false };
  return { status: 202, enqueue: true, egress: true };
}

